Mongo 4.2, driver version 3.5

When using *stream* method on cursor with Node 14 event close is emitted twice.

Here is a reproduction example:
{code:javascript}const {Writable} = require('stream');
const MongoClient = require('mongodb').MongoClient;

const url = 'mongodb://localhost:27017';
const dbName = 'dev';

const stdout = new Writable({
    objectMode: true,
    write(chunk, encoding, next) {
        console.log(chunk);
        return next(null, chunk);
    }
});

function process(next) {
    MongoClient.connect(url, function(err, client) {
        console.log("Connected successfully to server");
        const db = client.db(dbName);
        const cursor = db.collection('test').find({});
        const sourceStream = cursor.stream();
        sourceStream
            .on('close', () => {
                console.log('close'); // printed twice
                client.close();
                next();
            })
            .pipe(stdout);
    });
}

process(() => console.log('END'));

{code}
This issue doesn't affect previous node versions.


I think it comes from the default autoDestroy option introduced in node 14. After ending the stream is automatically destroyed and a close event is emitted in addition to the close event emitted by the driver.

At the moment, I have not found any way to override autoDestroy option used for the cursor.

Pipelining an upload stream you've created with GridFSBucket.
openUploadStream worked on Node v12.20.1 and v10.23.0, but it never finishes on Node v14.16.0.
 
{code:java}
async function test() {
    const mongoClient = await mongodb.MongoClient.connect('mongodb://localhost', {
        useUnifiedTopology: true
    });
    const mongoDb = mongoClient.db('test');
    const bucket = new mongodb.GridFSBucket(mongoDb, {
        bucketName: 'testBucket'
    });

    const fileStream = fs.createReadStream('test.js');
    const uploadStream = bucket.openUploadStream('test');
    await util.promisify(stream.pipeline)(fileStream, uploadStream);
}
{code}
You can find the whole test at https://github.com/snakamura/mongodb-fsbucket-pipeline.

